return [{
  json: {
    supabaseUrl: 'https://bzicdqrbqykypzesxayw.supabase.co',
    supabaseServiceKey: $env.SUPABASE_SERVICE_KEY,
    chatwootUrl: 'https://chatwoot.aquimaq.com.br',
    chatwootToken: $env.CHATWOOT_ACCESS_TOKEN,
    chatwootAccountId: 2,
    // ID da conversa "Sistema Aquimaq" no Chatwoot (criada via API, contato_id=27)
    chatwootConvId: 6
  }
}];

const config = $('Config').first().json;
const items = $input.all();
if (items.length === 0) return [];

// n8n HTTP Request v4 já divide arrays em itens separados automaticamente
return items.map(item => ({
  json: { ...item.json, _config: config }
}));

const event = $json;
const payload = event.payload || {};
const order = payload.order || {};

const emojis = {
  'order.created':         '🛒',
  'order.pago':            '✅',
  'order.em_separacao':    '📦',
  'order.enviado':         '🚚',
  'order.entregue':        '🏠',
  'order.cancelado':       '❌',
  'order.pronto_retirada': '🏪'
};
const labels = {
  'order.created':         'Novo Pedido',
  'order.pago':            'Pagamento Confirmado',
  'order.em_separacao':    'Em Separação',
  'order.enviado':         'Pedido Enviado',
  'order.entregue':        'Pedido Entregue',
  'order.cancelado':       'Pedido Cancelado',
  'order.pronto_retirada': 'Pronto para Retirada'
};

const emoji = emojis[event.event_type] || '📋';
const label = labels[event.event_type] || event.event_type;
const orderId = order.id ? String(order.id).substring(0, 8).toUpperCase() : 'N/A';
const total = order.total != null ? `R$ ${Number(order.total).toFixed(2).replace('.', ',')}` : 'N/A';
const cliente = order.cliente_email || order.cliente_nome || order.cliente_id || 'N/A';
const shipping = order.shipping_method || 'N/A';
const status = order.status || 'N/A';
const tracking = order.tracking_code ? `\n🔍 Rastreio: ${order.tracking_code}` : '';
const dt = new Date(event.created_at).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

const message = `${emoji} **${label}**\n\n🆔 Pedido: ${orderId}\n👤 Cliente: ${cliente}\n💰 Total: ${total}\n📮 Envio: ${shipping}\n📊 Status: ${status}${tracking}\n\n_${dt}_`;

return [{ json: { ...event, _message: message } }];
